-- INVOICES
INSERT INTO invoices (hotel_id, reservation_id, amount, status, issued_at)
SELECT r.hotel_id, r.id, COALESCE(r.total_price,0)*1.13, 'paid', (r.check_out::timestamp + interval '1 hour')
FROM reservations r
WHERE r.hotel_id = '5584eba7-506a-4fd4-90bb-875749724839' AND r.status = 'completed';

